{
  "verses": [
    {
      "n": 24,
      "column": "left",
      "text": "Un ta fazzija us winnu:\nes efinu fawu Nammu fatattijis/\nEs efinu Betuëta Milkas Deh-\nla Meita / ko ta taim Naöram\ndsemdejji.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Un ta fazzija wehl us win-\nnu/ tur irr arridsan Pellawas/un\ndauds Barribas pee mums/ ir\nMahjoschanas-Weeta.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Tad tas Wihrs preeksch\nta KUNGA nomesdamees / pee-\nluhose to.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Un fazzija: Slatwehts laid\nirr tas KUNGS/ manna Kunga\nAbräima DEews / kas ne irr at-\nrahwis fawu Scheblastibu / un\nPateetibu no manna Kunga :\nkas mann peenahk / tad irr tas\nKUNGS mann waddijs to Zet-\nfu / us manna Kunga Bruhta\nNamnu.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Un ta Meitina tezzeja/ un\npafazzija to paſchu fawas Mah-\ntes Namnâ/\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Un Rebekkai bij weens\nBrahlis / Lahbans Wahrdá/ un\nLahbans tezzeja pee ta Wihra ah-\nra/ us Akku.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Un kad wiꞥſch tohs Roh-\nku-Gredsenus / un tahs Peeres-\nSprahdses fawas Mahfas Roh-\nkâs redsejis / un fawas Mahfas\nRebekkas Wahrdus dſirdejts bij/\nkas fazzija / ta irr tas Wihrs us\nman runnajis / tad nahze tas pee\nta Wihra/ un raugi/ tas stahwe-\nja pee teen Kaneeteem / pee tahs\nAkfas.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Un wiꞥſch fazzija: Nahz\neekscha / tu Swehtihts ta KUN-\nGA / kam tu stahwi ahrá / jo\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Tad nahze tas Wihrs\nNamnâ / un tee Kaneeti tappe\nnomettinati/ un teem Kaneeteem\ntappe Pellawas un Barriba doh-\nta / un Uhdens winna Kahjas\nmasgaht / un to Wibru Kahjas/\nkas ar winnu bija.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Un tee uſzehle winnam\nBarribu / bet winſch fazzija : Ee\nne ehdiſchn / teekams es fawue\nWahrdus efinu runnajis / un\nwinſch fazzija : runna.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Tad fazzija tas: Es efinu\nAhbräima Kalps/\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Un tas KUNGS / ir\nmannu Kungu baggatigi fwehti\njis / un tas irr augamo audsis\nun wiſch irr tam dewis Awis un\nWehrfchus/un Sudrabu un Se-\ntu / un Kalpus un Kalpones/ un\nKaneetus un Ehsetus.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Un Sara / wanna Kung-\nSeewa / irr mannam Kunga-\nweenu Dehlu dsemdejti/ pehz to\nkad ta bij wezza tapputi/ un tan\nirr wiſch dewis wiſju/ kas win-\nnam peederr.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Un mans Kungs irr man-\nlizzis swehreht / fazzidams : Ten\nne buhs mannain Dehlam See-\nwu reint/ no tahm Kananiter-\nMeitahn / ka Semine es dfih\nwoju.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Bet tew buhs eet us man-\nna Tehwa Namnu / un pee man-\nneem Raddeem / un mannam\nDehlam Seewu reint.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
